import{_ as a,o as r,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"🫘 黃豆追蹤日誌 — 2026-05-02","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-02.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-02.md"}'),s={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-02.md"};function n(i,e,l,c,h,m){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="🫘-黃豆追蹤日誌-—-2026-05-02" tabindex="-1">🫘 黃豆追蹤日誌 — 2026-05-02 <a class="header-anchor" href="#🫘-黃豆追蹤日誌-—-2026-05-02" aria-label="Permalink to &quot;🫘 黃豆追蹤日誌 — 2026-05-02&quot;">​</a></h1><blockquote><p>掃描時間：2026-05-02 Asia/Taipei 10:40 搜尋工具：web_search (Google Search grounding)</p></blockquote><hr><h2 id="📋-8-項追蹤指標" tabindex="-1">📋 8 項追蹤指標 <a class="header-anchor" href="#📋-8-項追蹤指標" aria-label="Permalink to &quot;📋 8 項追蹤指標&quot;">​</a></h2><h3 id="_1-現貨價" tabindex="-1">1. 現貨價 <a class="header-anchor" href="#_1-現貨價" aria-label="Permalink to &quot;1. 現貨價&quot;">​</a></h3><p><strong>1,185-1,187 美分/蒲式耳</strong>（5/1-5/2，日 +0.42%）。年漲約 13%。 <em>來源：TradingEconomics (2026-05-02) — <a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/soybeans</a></em></p><h3 id="_2-期貨價-近月-遠月" tabindex="-1">2. 期貨價（近月/遠月） <a class="header-anchor" href="#_2-期貨價-近月-遠月" aria-label="Permalink to &quot;2. 期貨價（近月/遠月）&quot;">​</a></h3><ul><li>CBOT 5 月（ZSK26）：5/1 收 <strong>$11.80½</strong>（-1.5¢）</li><li>CBOT 7 月：<strong>1,191</strong>（+2¢）</li><li>12 個月目標：<strong>1,225.89</strong> 美分 <em>來源：CME Group (2026-05-02) — <a href="https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html" target="_blank" rel="noreferrer">https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html</a>, Mysteel</em></li></ul><h3 id="_3-技術線-ma20-ma60" tabindex="-1">3. 技術線（MA20/MA60） <a class="header-anchor" href="#_3-技術線-ma20-ma60" aria-label="Permalink to &quot;3. 技術線（MA20/MA60）&quot;">​</a></h3><ul><li>價格 1,185 維持在 MA20 和 MA60 之上，多頭排列</li><li>六週高點動能持續，接近 1,200 阻力位</li><li>4 月迄今累漲約 1.7% <em>來源：TradingEconomics (2026-05-02)</em></li></ul><h3 id="_4-庫存數據" tabindex="-1">4. 庫存數據 <a class="header-anchor" href="#_4-庫存數據" aria-label="Permalink to &quot;4. 庫存數據&quot;">​</a></h3><ul><li>2025/26 年度全球供應充裕（巴西 + 美國豐收）</li><li>USDA 預估累計銷售達全年預測的 <strong>88.4%</strong></li><li>需週均銷售 23 萬噸才能達 USDA 全年目標 <em>來源：USDA FAS (2026-05-01)</em></li></ul><h3 id="_5-出口銷售" tabindex="-1">5. 出口銷售 <a class="header-anchor" href="#_5-出口銷售" aria-label="Permalink to &quot;5. 出口銷售&quot;">​</a></h3><ul><li>USDA 截至 4/23 週出口 <strong>261,100 噸</strong>（年度次低）</li><li>新作銷售僅 <strong>2,980 噸</strong>，顯示中國採購謹慎</li><li>中國 2026/27 產季進口預估：USDA 看增至 <strong>1.08 億噸</strong>；中國農業部預測減至 <strong>8,255 萬噸</strong>（-6.1%） <em>來源：Morningstar (2026-04-30) — <a href="https://www.morningstar.com/news/dow-jones/2026043011373/soybean-export-sales-land-on-low-end-of-forecasts" target="_blank" rel="noreferrer">https://www.morningstar.com/news/dow-jones/2026043011373/soybean-export-sales-land-on-low-end-of-forecasts</a>, Chinadaily</em></li></ul><h3 id="_6-天氣狀況" tabindex="-1">6. 天氣狀況 <a class="header-anchor" href="#_6-天氣狀況" aria-label="Permalink to &quot;6. 天氣狀況&quot;">​</a></h3><ul><li>🇺🇸 <strong>美國</strong>：已種植 23%（五年均 12%），8% 已出苗。5/5-9 中部偏冷、偏乾，利於種植推進。</li><li>🇦🇷 <strong>阿根廷</strong>：聖塔菲省持續降雨使收割僅 10%（季節平均 60%），仍為主憂。</li><li>🇧🇷 <strong>巴西</strong>：豐收確認，南里奧格蘭德降雨偏低但影響有限。 <em>來源：FarmProgress (2026-05-02) — <a href="https://www.farmprogress.com/marketing/headline-grain-markets-face-mixed-signals-as-spring-progresses-with-argentina-corn-exports-and-hrw-wheat-drought-in-focus" target="_blank" rel="noreferrer">https://www.farmprogress.com/marketing/headline-grain-markets-face-mixed-signals-as-spring-progresses-with-argentina-corn-exports-and-hrw-wheat-drought-in-focus</a>, RFD TV</em></li></ul><h3 id="_7-美元指數影響" tabindex="-1">7. 美元指數影響 <a class="header-anchor" href="#_7-美元指數影響" aria-label="Permalink to &quot;7. 美元指數影響&quot;">​</a></h3><p>DXY <strong>98.21</strong>（5/1，月跌 1.80%）。預測年底可能跌至 <strong>94.61-98.47</strong>，若續走弱將支撐商品價格。 <em>來源：TradingEconomics (2026-05-02) — <a href="https://tradingeconomics.com/united-states/currency" target="_blank" rel="noreferrer">https://tradingeconomics.com/united-states/currency</a>, AhaSignals</em></p><h3 id="_8-基金淨持倉" tabindex="-1">8. 基金淨持倉 <a class="header-anchor" href="#_8-基金淨持倉" aria-label="Permalink to &quot;8. 基金淨持倉&quot;">​</a></h3><p>CFTC 截至 4/24 投機淨多頭 <strong>211.1K</strong>。基金持續削減淨多頭（連續第二週），反映對短期價格的謹慎態度。 <em>來源：CFTC via MQL5 (2026-05-01)</em></p><hr><h2 id="🗞️-5-條黃豆相關新聞" tabindex="-1">🗞️ 5 條黃豆相關新聞 <a class="header-anchor" href="#🗞️-5-條黃豆相關新聞" aria-label="Permalink to &quot;🗞️ 5 條黃豆相關新聞&quot;">​</a></h2><h3 id="新聞-1-cbot-黃豆-5-月合約小幅回落-7-月走強" tabindex="-1">新聞 1：CBOT 黃豆 5 月合約小幅回落，7 月走強 <a class="header-anchor" href="#新聞-1-cbot-黃豆-5-月合約小幅回落-7-月走強" aria-label="Permalink to &quot;新聞 1：CBOT 黃豆 5 月合約小幅回落，7 月走強&quot;">​</a></h3><p>5/2 5 月合約收 $11.80½（-1.5¢），7 月合約 1,191（+2¢），近遠月價差收窄反映庫存壓力。 <em>來源：CME Group — <a href="https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html" target="_blank" rel="noreferrer">https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html</a></em></p><h3 id="新聞-2-中國-2026-年進口預測出現分歧" tabindex="-1">新聞 2：中國 2026 年進口預測出現分歧 <a class="header-anchor" href="#新聞-2-中國-2026-年進口預測出現分歧" aria-label="Permalink to &quot;新聞 2：中國 2026 年進口預測出現分歧&quot;">​</a></h3><p>USDA FAS 預測增至 1.08 億噸；但中國農業部預測減至 8,255 萬噸（-6.1%），稱因國內增產和需求放緩。3 月進口 402 萬噸低於預期（巴西檢疫延遲）。 <em>來源：Chinadaily (2026-04-20) — <a href="https://www.chinadaily.com.cn/a/202604/20/WS69e5f017a310d6866eb4473b.html" target="_blank" rel="noreferrer">https://www.chinadaily.com.cn/a/202604/20/WS69e5f017a310d6866eb4473b.html</a>, UkrAgroConsult</em></p><h3 id="新聞-3-美國種植進度超前-23-已種植" tabindex="-1">新聞 3：美國種植進度超前，23% 已種植 <a class="header-anchor" href="#新聞-3-美國種植進度超前-23-已種植" aria-label="Permalink to &quot;新聞 3：美國種植進度超前，23% 已種植&quot;">​</a></h3><p>截至 4/28 黃豆種植 23%（五年均 12%），8% 已出苗（五年均 1%）。南方州因土壤溫度較高出苗率最高。5/5-9 天氣預測偏冷偏乾，利於種植推進。 <em>來源：RFD TV (2026-05-01) — <a href="https://www.rfdtv.com/crop-progress-recap-strong-planting-pace-meets-weather-risks-and-quality-concerns" target="_blank" rel="noreferrer">https://www.rfdtv.com/crop-progress-recap-strong-planting-pace-meets-weather-risks-and-quality-concerns</a></em></p><h3 id="新聞-4-阿根廷收割嚴重落後-僅-10-完成" tabindex="-1">新聞 4：阿根廷收割嚴重落後，僅 10% 完成 <a class="header-anchor" href="#新聞-4-阿根廷收割嚴重落後-僅-10-完成" aria-label="Permalink to &quot;新聞 4：阿根廷收割嚴重落後，僅 10% 完成&quot;">​</a></h3><p>聖塔菲省持續降雨使黃豆收割進度僅達季節平均的 1/6。若天氣未改善，可能影響品質和產量。 <em>來源：Kpler — <a href="https://www.kpler.com/blog/south-america-weather-risk-puts-global-corn-and-soybean-supply-on-edge" target="_blank" rel="noreferrer">https://www.kpler.com/blog/south-america-weather-risk-puts-global-corn-and-soybean-supply-on-edge</a></em></p><h3 id="新聞-5-荷莫茲封閉持續影響肥料供應鏈" tabindex="-1">新聞 5：荷莫茲封閉持續影響肥料供應鏈 <a class="header-anchor" href="#新聞-5-荷莫茲封閉持續影響肥料供應鏈" aria-label="Permalink to &quot;新聞 5：荷莫茲封閉持續影響肥料供應鏈&quot;">​</a></h3><p>荷莫茲海峽封閉第 64 天，影響全球 40% 尿素出口。世界銀行預測 2026 年肥料價格上漲超 30%，農民轉向施肥需求較低的黃豆（面積 +4% vs 玉米 -3%）。 <em>來源：World Bank (2026-04-28)</em></p><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>web_search (2026-05-02): TradingEconomics Soybean — <a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/soybeans</a></li><li>web_search (2026-05-02): CME Group Soybean — <a href="https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html" target="_blank" rel="noreferrer">https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html</a></li><li>web_search (2026-04-30): Morningstar USDA Export — <a href="https://www.morningstar.com/news/dow-jones/2026043011373/soybean-export-sales-land-on-low-end-of-forecasts" target="_blank" rel="noreferrer">https://www.morningstar.com/news/dow-jones/2026043011373/soybean-export-sales-land-on-low-end-of-forecasts</a></li><li>web_search (2026-05-01): RFD TV Crop Progress — <a href="https://www.rfdtv.com/crop-progress-recap-strong-planting-pace-meets-weather-risks-and-quality-concerns" target="_blank" rel="noreferrer">https://www.rfdtv.com/crop-progress-recap-strong-planting-pace-meets-weather-risks-and-quality-concerns</a></li><li>web_search (2026-04-20): Chinadaily China Import — <a href="https://www.chinadaily.com.cn/a/202604/20/WS69e5f017a310d6866eb4473b.html" target="_blank" rel="noreferrer">https://www.chinadaily.com.cn/a/202604/20/WS69e5f017a310d6866eb4473b.html</a></li><li>web_search (2026-05-02): FarmProgress Weather — <a href="https://www.farmprogress.com/marketing/headline-grain-markets-face-mixed-signals-as-spring-progresses-with-argentina-corn-exports-and-hrw-wheat-drought-in-focus" target="_blank" rel="noreferrer">https://www.farmprogress.com/marketing/headline-grain-markets-face-mixed-signals-as-spring-progresses-with-argentina-corn-exports-and-hrw-wheat-drought-in-focus</a></li><li>web_search (2026-05-02): TradingEconomics DXY — <a href="https://tradingeconomics.com/united-states/currency" target="_blank" rel="noreferrer">https://tradingeconomics.com/united-states/currency</a></li><li>web_search (2026-05-01): CFTC via MQL5 — <a href="https://www.mql5.com/en/economic-calendar/united-states/cftc-soybeans-non-commercial-net-positions" target="_blank" rel="noreferrer">https://www.mql5.com/en/economic-calendar/united-states/cftc-soybeans-non-commercial-net-positions</a></li></ol><hr><p><em>報告產出：Dr.32 知識管家 | 抓取時間：2026-05-02 Asia/Taipei 10:40</em></p>',37)])])}const p=a(s,[["render",n]]);export{g as __pageData,p as default};
